1	import html_to_pdf from "html-pdf-node";
2	import { getCvHtml } from "../utils/cv-html";
3	
4	const options = { format: "A4", timeout: 20000 };
5	
6	export const GET = async () => {
7	  try {
8	    const content = getCvHtml();
9	    const file = { content };
10	    const buffer = await html_to_pdf.generatePdf(file, options);
11	
12	    return new Response(buffer, {
13	      headers: {
14	        "Content-Type": "application/pdf",
15	        "Content-Disposition": 'attachment; filename="andrii-popenko-cv.pdf"',
16	      },
17	    });
18	  } catch (error) {
19	    throw new Error(`PDF generation failed: ${error}`);
20	  }
21	};
